mapper.select:
	/* selectActiveSubscriber */
    SELECT
    	COUNT(*)
    FROM
    	${schema}.eml_subs
    WHERE 
		user_nm = #{userNm}
		AND mpno_pfx = #{mpnoPfx}
		AND mpno_mid = #{mpnoMid}
		AND mpno_sfx = #{mpnoSfx}
		AND eml_lcal = #{emlLcal}
		AND eml_dmn = #{emlDmn}
		AND sub_stat_cd = 'SUB'

mapper.insert:
	/* insertEmailAuth */
    INSERT INTO ${schema}.eml_cert (
        eml_lcal,
        eml_dmn,
        cert_cd
    ) VALUES (
        #{emlLcal}
        , #{emlDmn}
        , #{certCd}
    )

INSERT INTO ${schema}.eml_cert_log (
