    #{emlDmn},
    #{emlCertSttsCd}
)

mapper.update:
/* updateSubscriber */
UPDATE ${schema}.eml_subs
SET 
    eml_lcal = #{newEmlLocal}, 
    eml_dmn = #{newEmlDmn},

    	inst_nm = #{instNm},


    	jbps_nm = #{jbpsNm},

    mdfcn_dt = CURRENT_TIMESTAMP,
    mdfcn_id = 'SYSTEM'
WHERE 
    user_nm = #{userNm}
    AND mpno_pfx = #{mpnoPfx}
    AND mpno_mid = #{mpnoMid}
    AND mpno_sfx = #{mpnoSfx}
    AND eml_lcal = #{emlLcal}
    AND eml_dmn = #{emlDmn}
    AND sub_stat_cd = 'SUB'
